from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
from flask_sslify import SSLify
from werkzeug.security import generate_password_hash, check_password_hash
from flask_bcrypt import Bcrypt
from flask_login import LoginManager, UserMixin, login_user, logout_user, login_required, current_user

app = Flask(__name__)
sslify = SSLify(app)
bcrypt = Bcrypt(app)

# Configure logging
handler = RotatingFileHandler('application.log', maxBytes=1000000, backupCount=1)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
logging.getLogger().addHandler(handler)

login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin):
    def __init__(self, id, username, password, email):
        self.id = id
        self.username = username
        self.password = generate_password_hash(password)
        self.email = email

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data['username']
    password = data['password']
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')
    
    logging.info(f'Login attempt: {username}, IP address: {ip_address}, User Agent: {user_agent}')
    
    user = User.query.filter_by(username=username).first()
    if user and check_password_hash(user.password, password):
        login_user(user)
        return jsonify({'message': 'Logged in successfully'}), 200
    else:
        logging.warning(f'Login failed for username: {username}, IP address: {ip_address}')
        return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/logout', methods=['POST'])
@login_required
def logout():
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')
    
    logging.info(f'Logout attempt, IP address: {ip_address}, User Agent: {user_agent}')
    
    logout_user()
    return jsonify({'message': 'Logged out successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)